#include <stdio.h>
#include <string.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        int cntStart = 0, cntLtime = 0;
        char buf[20];
        for (int i = 0; i < N; ++i) {
            scanf("%s", buf);
            if (strcmp(buf, "START38") == 0) cntStart++;
            else cntLtime++;
        }
        printf("%d %d\n", cntStart, cntLtime);
    }
    return 0;
}

