import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        cnt_start = 0
        cnt_ltime = 0
        for _ in range(N):
            token = next(it)
            if token == "START38":
                cnt_start += 1
            else:
                cnt_ltime += 1
        out_lines.append(f"{cnt_start} {cnt_ltime}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

